(function() {
    // Функция инициализации спойлеров
    window.initSpoilers = function(container) {
        const selector = container || "body";
        const $container = jQuery(selector);

        // Используем делегирование событий для надежности
        $container.on("click", "div.spoiler-head", function() {
            const $head = jQuery(this);
            const $body = $head.next("div.spoiler-body");

            $head.toggleClass("unfolded");
            $body.stop(true, true).slideToggle("slow");
        });
    };

    // Проверяем наличие jQuery, если его нет — выводим ошибку в консоль
    if (typeof jQuery === "undefined") {
        console.error("Ошибка: Для работы спойлеров требуется библиотека jQuery.");
        return;
    }

    // Запускаем при загрузке страницы
    jQuery(document).ready(function() {
        window.initSpoilers();
    });
})();